+          {collectionLogs.map((log) => (
+            <li key={log.id}>
+              {log.step} / {log.status} - {log.message}
+            </li>
+          ))}
+        </ul>
+      </section>
+
+      {report.sections.map((section) => (
+        <article className="section-card" key={section.id}>
+          <h2>{section.title}</h2>
+          <p>{section.body}</p>
+        </article>
+      ))}
+
+      <section className="section-card">
