+        <h2>Risks</h2>
+        <ul className="detail-list">
+          {report.risks.map((item) => (
+            <li key={item}>{item}</li>
+          ))}
+        </ul>
+      </section>
+
+      <section className="section-card">
+        <h2>Update Log</h2>
+        <ul className="detail-list">
+          {report.updateLog.map((item) => (
